184→// Latest returns the path to the most recently dated archive file matching
185→// "{name}-*.{ext}.xz" in the cache directory. Returns ("", false) if none exist.
186→//
187→// Files are named with ISO dates (e.g. nces-2026-03-09.csv.xz) so lexicographic
188→// sort gives the correct newest-first order.
189→func (f *Fetcher) Latest(name, ext string) (string, bool) {
190→	pattern := filepath.Join(f.cacheDir, fmt.Sprintf("%s-*.%s.xz", name, ext))
191→	matches, err := filepath.Glob(pattern)
192→	if err != nil || len(matches) == 0 {
193→		return "", false
194→	}
195→	sort.Strings(matches)
196→	return matches[len(matches)-1], true
197→}
